// ShareActivity.kt
package com.example.shareapp

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import java.io.File
import java.io.FileOutputStream

class ShareActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        when {
            intent?.action == Intent.ACTION_SEND -> {
                if (intent.type?.startsWith("text/") == true) {
                    handleSharedText(intent)
                } else if (intent.type?.startsWith("image/") == true) {
                    handleSharedImage(intent)
                }
            }
            intent?.action == Intent.ACTION_SEND_MULTIPLE -> {
                handleMultipleImages(intent)
            }
            else -> {
                Toast.makeText(this, "Unsupported share action", Toast.LENGTH_SHORT).show()
                finish()
            }
        }
    }

    private fun handleSharedText(intent: Intent) {
        intent.getStringExtra(Intent.EXTRA_TEXT)?.let { sharedText ->
            processSharedText(sharedText)
        }
    }

    private fun handleSharedImage(intent: Intent) {
        (intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM))?.let { imageUri ->
            processSharedImage(imageUri)
        }
    }

    private fun handleMultipleImages(intent: Intent) {
        intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)?.let { imageUris ->
            processMultipleImages(imageUris)
        }
    }

    private fun processSharedText(text: String) {
        val urlPattern = Regex("https?://[^\\s]+")
        val urls = urlPattern.findAll(text).map { it.value }.toList()
        
        if (urls.isNotEmpty()) {
            Toast.makeText(this, "Found ${urls.size} URL(s): ${urls.joinToString()}", Toast.LENGTH_LONG).show()
        } else {
            Toast.makeText(this, "Shared text: $text", Toast.LENGTH_LONG).show()
        }
        
        finish()
    }

    private fun processSharedImage(imageUri: Uri) {
        try {
            val inputStream = contentResolver.openInputStream(imageUri)
            val file = File(filesDir, "shared_image_${System.currentTimeMillis()}.jpg")
            
            inputStream?.use { input ->
                FileOutputStream(file).use { output ->
                    input.copyTo(output)
                }
            }
            
            Toast.makeText(this, "Image saved: ${file.absolutePath}", Toast.LENGTH_LONG).show()
        } catch (e: Exception) {
            Toast.makeText(this, "Error processing image: ${e.message}", Toast.LENGTH_SHORT).show()
        }
        
        finish()
    }

    private fun processMultipleImages(imageUris: List<Uri>) {
        var successCount = 0
        
        imageUris.forEachIndexed { index, uri ->
            try {
                val inputStream = contentResolver.openInputStream(uri)
                val file = File(filesDir, "shared_image_${System.currentTimeMillis()}_$index.jpg")
                
                inputStream?.use { input ->
                    FileOutputStream(file).use { output ->
                        input.copyTo(output)
                    }
                }
                successCount++
            } catch (e: Exception) {
                // Continue processing remaining images
            }
        }
        
        Toast.makeText(this, "Saved $successCount of ${imageUris.size} images", Toast.LENGTH_LONG).show()
        finish()
    }
}